1	//! MPSC ring: multi-producer single-consumer sibling of the
2	//! SPSC ring, per the design doc's "MPSC ring (sibling
3	//! primitive)" section:
4	//!
5	//! - Same region shape as the SPSC ring — a four-line
6	//!   [`MpscHeader`] then slots — plus a per-slot sequence
7	//!   array between them: `seq[pos]` publishes each slot
8	//!   independently, because claim order and commit order
9	//!   differ under concurrent producers.
10	//! - Producers CAS-claim `producer_idx`; the consumer stays
11	//!   CAS-free. Fullness is read from the slot seq, so
12	//!   producers never load `consumer_idx`.
13	//! - Own magic and layout version: a region is one kind or
14	//!   the other, and cross-attaching fails toward
15	//!   [`Error::BadMagic`].
16	//! - The claim CAS raises the atomic floor for MPSC users
17	//!   only — this module is gated on `target_has_atomic =
18	//!   "32"`; the SPSC ring stays load/store-only.
19	
20	use core::marker::PhantomData;
21	use core::mem::size_of;
22	use core::sync::atomic::{AtomicU32, Ordering};
23	
24	use crate::{CACHE_LINE_SIZE, CacheAligned, Error, USER_WORDS};
25	
26	mod consumer;
27	mod producer;
28	
29	pub use consumer::{MpscConsumer, MpscReadSlot};
30	pub use producer::MpscProducer;
31	
32	/// Layout marker written by [`MpscRing::init`]; distinct from
33	/// the SPSC magic so cross-kind attach fails toward
34	/// [`Error::BadMagic`].
35	const MPSC_MAGIC: u32 = 0x5A43_4D31; // "ZCM1"
36	
37	/// Bumped on any change to the MPSC region layout;
38	/// independent of the SPSC layout version.
39	const MPSC_LAYOUT_VERSION: u32 = 1;
40	
41	/// Capacity bound: `2^30`, not the SPSC `2^31` — the seq
42	/// tombstone encoding reserves index-arithmetic headroom (see
43	/// the design doc's "MPSC open questions").
44	const MPSC_MAX_CAPACITY: u32 = 1 << 30;
45	
46	/// Tombstone offset: an unwound `send_with` commits
47	/// `pos + 1 + TOMBSTONE` instead of `pos + 1`, marking a
48	/// claimed slot the consumer must release without delivering.
49	///
50	/// - Unambiguous at both wait points: the consumer at `c`
51	///   legitimately sees only `seq - (c+1)` of `-1` (not yet
52	///   committed) or `0` (committed), so exactly `2^31` means
53	///   tombstone; a producer's wrapping-signed diff reads a
54	///   tombstoned previous lap as negative — "full" — until the
55	///   consumer skips it, which is the correct backpressure.
56	pub(crate) const TOMBSTONE: u32 = 1 << 31;
57	
58	/// Control block at offset 0 of an MPSC region — same
59	/// four-line shape as the SPSC [`Header`](crate::Header), but
60	/// its own type: the layouts evolve independently and the
61	/// index-ownership story differs.
62	///
63	/// - line 0: geometry, written by [`MpscRing::init`] with
64	///   `magic` last (`Release`), read-only thereafter.
65	/// - line 1: `producer_idx` — CAS-claimed by *all* producers
66	///   (the contended line), never read by the consumer's hot
67	///   path.
68	/// - line 2: `consumer_idx` — written only by the consumer;
69	///   never read by producers (fullness comes from the slot
70	///   seq), so it is resume state and diagnostic occupancy.
71	/// - line 3: `user`, app-owned scratch — same contract as the
72	///   SPSC user line.
73	/// - Every field is atomic: the region may be mapped by a
74	///   peer at any time.
75	#[repr(C)]
76	pub struct MpscHeader {
77	    /// Layout marker ([`MPSC_MAGIC`]); stored last by init
78	    /// (`Release`), loaded first by attach (`Acquire`).
79	    magic: AtomicU32,
80	    /// Layout version ([`MPSC_LAYOUT_VERSION`]).
81	    layout_version: AtomicU32,
82	    /// Slot size N in bytes — a [`CACHE_LINE_SIZE`] multiple.
83	    slot_size: AtomicU32,
84	    /// Slot count M — a power of two `<= 2^30`.
85	    capacity: AtomicU32,
86	    /// [`CACHE_LINE_SIZE`] this region was built with.
87	    cache_line_size: AtomicU32,
88	    /// Free-running count of slot positions claimed by
89	    /// producers (CAS).
90	    producer_idx: CacheAligned<AtomicU32>,
91	    /// Free-running count of messages released; consumer-owned
92	    /// resume state, not read by producers.
93	    consumer_idx: CacheAligned<AtomicU32>,
94	    /// App-owned scratch line ([`USER_WORDS`] words): zeroed by
95	    /// init, then never touched by the crate.
96	    user: CacheAligned<[AtomicU32; USER_WORDS]>,
97	}
98	
99	const _: () = assert!(size_of::<MpscHeader>() == 4 * CACHE_LINE_SIZE);
100	
101	/// A validated view over an MPSC ring region.
102	///
103	/// - Geometry is snapshotted out of the header at init/attach,
104	///   as the SPSC ring does: per-op paths never re-read fields
105	///   a peer could scribble on.
106	/// - Region layout: [`MpscHeader`], the seq array (`M ×
107	///   AtomicU32`, padded up to a cache line), then M slots of N
108	///   bytes.
109	pub struct MpscRing<'a> {
110	    /// The region's control block.
111	    header: &'a MpscHeader,
112	    /// Base of the per-slot sequence array.
113	    seqs: *const AtomicU32,
114	    /// Base of the slot array.
115	    slots: *mut u8,
116	    /// Snapshot of `header.slot_size`.
117	    slot_size: u32,
118	    /// Snapshot of `header.capacity`.
119	    capacity: u32,
120	    /// Slot-position mask (`capacity - 1`).
121	    mask: u32,
122	    _region: PhantomData<&'a [u8]>,
123	}
124	
125	impl<'a> MpscRing<'a> {
126	    /// Initialize a fresh region and return the ring over it.
127	    ///
128	    /// - `slot_size` — N bytes per slot, a [`CACHE_LINE_SIZE`]
129	    ///   multiple.
130	    /// - `capacity` — M slots, a power of two `<= 2^30`.
131	    /// - The region must be [`CACHE_LINE_SIZE`]-aligned and at
132	    ///   least [`mpsc_region_size`] bytes.
133	    pub fn init(region: &'a mut [u8], slot_size: u32, capacity: u32) -> Result<Self, Error> {
134	        validate_mpsc_geometry(slot_size, capacity)?;
135	        let len = region.len();
136	        // Taken exactly once — see `Ring::init` for the Stacked
137	        // Borrows rationale.
138	        let base = region.as_mut_ptr();
139	        let header = mpsc_header_ptr(base, len)?;
140	        if (len as u64) < mpsc_region_size(slot_size, capacity) {
141	            return Err(Error::TooSmall);
142	        }
143	        // SAFETY: alignment + room for the MpscHeader checked
144	        // by mpsc_header_ptr; region is exclusively borrowed
145	        // for 'a; any byte pattern is a valid MpscHeader
146	        // (all-atomic fields, plain-byte padding).
147	        let header = unsafe { &*header };
148	        header
149	            .layout_version
150	            .store(MPSC_LAYOUT_VERSION, Ordering::Relaxed);
151	        header.slot_size.store(slot_size, Ordering::Relaxed);
152	        header.capacity.store(capacity, Ordering::Relaxed);
153	        header
154	            .cache_line_size
155	            .store(CACHE_LINE_SIZE as u32, Ordering::Relaxed);
156	        header.producer_idx.store(0, Ordering::Relaxed);
157	        header.consumer_idx.store(0, Ordering::Relaxed);
158	        for word in header.user.iter() {
159	            word.store(0, Ordering::Relaxed);
160	        }
161	        // SAFETY: in bounds — len covers header + seq array.
162	        let seqs = unsafe { base.add(size_of::<MpscHeader>()) } as *const AtomicU32;
163	        // seq[i] = i marks every slot claimable by the position
164	        // that will first reach it.
165	        for i in 0..capacity {
166	            // SAFETY: i < capacity, inside the seq array
167	            // validated by the region-size check.
168	            unsafe { &*seqs.add(i as usize) }.store(i, Ordering::Relaxed);
169	        }
170	        // Published last: a peer that pre-mapped the region must
171	        // never observe the magic before the geometry and seq
172	        // stores it validates and relies on.
173	        header.magic.store(MPSC_MAGIC, Ordering::Release);
174	        // SAFETY: in bounds — len covers header + seqs + slots.
175	        let slots = unsafe { base.add(slots_offset(capacity)) };
176	        Ok(MpscRing {
177	            header,
178	            seqs,
179	            slots,
180	            slot_size,
181	            capacity,
182	            mask: capacity - 1,
183	            _region: PhantomData,
184	        })
185	    }
186	
187	    /// Attach to a region another process (or an earlier call)
188	    /// already initialized, validating its header.
189	    ///
190	    /// # Safety
191	    ///
192	    /// - `region` points to `len` bytes of memory that outlive
193	    ///   `'a`, genuinely shared and writable (e.g. a
194	    ///   `MAP_SHARED` mapping).
195	    /// - At most one consumer attaches; any number of
196	    ///   producers may (MPSC contract).
197	    pub unsafe fn attach(region: *mut u8, len: usize) -> Result<Self, Error> {
198	        let header = mpsc_header_ptr(region, len)?;
199	        // SAFETY: alignment + room for the MpscHeader checked
200	        // by mpsc_header_ptr; caller guarantees the memory is
201	        // live and shared.
202	        let header = unsafe { &*header };
203	        // Acquire pairs with init's Release store of magic: a
204	        // valid magic means the geometry and seq stores are
205	        // visible.
206	        if header.magic.load(Ordering::Acquire) != MPSC_MAGIC {
207	            return Err(Error::BadMagic);
208	        }
209	        if header.layout_version.load(Ordering::Relaxed) != MPSC_LAYOUT_VERSION {
210	            return Err(Error::BadLayoutVersion);
211	        }
212	        if header.cache_line_size.load(Ordering::Relaxed) != CACHE_LINE_SIZE as u32 {
213	            return Err(Error::BadCacheLine);
214	        }
215	        // Snapshot geometry once; per-op paths never re-read it.
216	        let slot_size = header.slot_size.load(Ordering::Relaxed);
217	        let capacity = header.capacity.load(Ordering::Relaxed);
218	        validate_mpsc_geometry(slot_size, capacity)?;
219	        if (len as u64) < mpsc_region_size(slot_size, capacity) {
220	            return Err(Error::TooSmall);
221	        }
222	        // SAFETY: in bounds — len covers header + seqs + slots.
223	        let seqs = unsafe { region.add(size_of::<MpscHeader>()) } as *const AtomicU32;
224	        // SAFETY: as above.
225	        let slots = unsafe { region.add(slots_offset(capacity)) };
226	        Ok(MpscRing {
227	            header,
228	            seqs,
229	            slots,
230	            slot_size,
231	            capacity,
232	            mask: capacity - 1,
233	            _region: PhantomData,
234	        })
235	    }
236	
237	    /// Split into one producer handle and the consumer handle.
238	    ///
239	    /// - The producer is `Clone`: one clone per producing
240	    ///   thread (MPSC contract). The consumer is unique per
241	    ///   process; cross-process, exactly one consuming process
242	    ///   is the caller's contract (see [`MpscRing::attach`]).
243	    pub fn split(self) -> (MpscProducer<'a>, MpscConsumer<'a>) {
244	        (
245	            MpscProducer::new(
246	                self.header,
247	                self.seqs,
248	                self.slots,
249	                self.slot_size,
250	                self.mask,
251	            ),
252	            MpscConsumer::new(
253	                self.header,
254	                self.seqs,
255	                self.slots,
256	                self.slot_size,
257	                self.capacity,
258	                self.mask,
259	            ),
260	        )
261	    }
262	}
263	
264	/// Validate a region base pointer and cast it to the
265	/// [`MpscHeader`] it must start with; shared by init / attach.
266	///
267	/// - Same split of duties as the SPSC `header_ptr`: alignment
268	///   and header room here, full-geometry length with the
269	///   caller.
270	fn mpsc_header_ptr(base: *mut u8, len: usize) -> Result<*const MpscHeader, Error> {
271	    if !(base as usize).is_multiple_of(CACHE_LINE_SIZE) {
272	        return Err(Error::Misaligned);
273	    }
274	    if len < size_of::<MpscHeader>() {
275	        return Err(Error::TooSmall);
276	    }
277	    Ok(base as *const MpscHeader)
278	}
279	
280	/// Bytes the seq array occupies, padded up to a cache line so
281	/// the slot array behind it stays line-aligned.
282	///
283	/// - u64: `capacity * 4` reaches `2^32` at the `2^30` cap,
284	///   which would wrap a 32-bit usize.
285	fn seq_bytes(capacity: u32) -> u64 {
286	    (capacity as u64 * size_of::<AtomicU32>() as u64).next_multiple_of(CACHE_LINE_SIZE as u64)
287	}
288	
289	/// Byte offset of the slot array: header, then the padded seq
290	/// array.
291	///
292	/// - usize return: callers offset a pointer with it, and only
293	///   after the u64 region-size check has proven the region —
294	///   hence this offset — fits in memory.
295	fn slots_offset(capacity: u32) -> usize {
296	    size_of::<MpscHeader>() + seq_bytes(capacity) as usize
297	}
298	
299	/// Bytes needed for an MPSC region with the given geometry.
300	///
301	/// - Computed in u64 for the same 32-bit wrap reason as the
302	///   SPSC `region_size`.
303	pub fn mpsc_region_size(slot_size: u32, capacity: u32) -> u64 {
304	    size_of::<MpscHeader>() as u64 + seq_bytes(capacity) + slot_size as u64 * capacity as u64
305	}
306	
307	/// Geometry checks for [`MpscRing::init`] / [`MpscRing::attach`].
308	///
309	/// - Slot size as the SPSC ring; capacity additionally capped
310	///   at [`MPSC_MAX_CAPACITY`] for tombstone headroom.
311	fn validate_mpsc_geometry(slot_size: u32, capacity: u32) -> Result<(), Error> {
312	    if slot_size == 0 || !(slot_size as usize).is_multiple_of(CACHE_LINE_SIZE) {
313	        return Err(Error::BadSlotSize);
314	    }
315	    if capacity == 0 || !capacity.is_power_of_two() || capacity > MPSC_MAX_CAPACITY {
316	        return Err(Error::BadCapacity);
317	    }
318	    Ok(())
319	}
