321	#[cfg(test)]
322	mod tests {
323	    use super::*;
324	    use crate::Ring;
325	
326	    /// Test region: header + seq line (4 × 4 B padded to 64) +
327	    /// 4 slots × 1 line.
328	    const REGION_BYTES: usize = size_of::<MpscHeader>() + CACHE_LINE_SIZE + (4 * CACHE_LINE_SIZE);
329	
330	    /// Cache-line-aligned backing store for the tests' rings.
331	    #[repr(C, align(64))]
332	    struct Region([u8; REGION_BYTES]);
333	
334	    impl Region {
335	        fn new() -> Self {
336	            Region([0; REGION_BYTES])
337	        }
338	    }
339	
340	    #[test]
341	    fn mpsc_region_size_accounts_for_seq_array() {
342	        // 4 slots: header 256 + seq 16→64 + slots 256 = 576.
343	        assert_eq!(mpsc_region_size(64, 4), 576);
344	        // 32 slots: seq 128 is already a line multiple.
345	        assert_eq!(
346	            mpsc_region_size(64, 32),
347	            (size_of::<MpscHeader>() + 128 + 32 * 64) as u64
348	        );
349	    }
350	
351	    #[test]
352	    fn mpsc_init_rejects_bad_geometry() {
353	        let mut r = Region::new();
354	        assert_eq!(
355	            MpscRing::init(&mut r.0, 63, 4).err().unwrap(),
356	            Error::BadSlotSize
357	        );
358	        assert_eq!(
359	            MpscRing::init(&mut r.0, 0, 4).err().unwrap(),
360	            Error::BadSlotSize
361	        );
362	        assert_eq!(
363	            MpscRing::init(&mut r.0, 64, 3).err().unwrap(),
364	            Error::BadCapacity
365	        );
366	        assert_eq!(
367	            MpscRing::init(&mut r.0, 64, 0).err().unwrap(),
368	            Error::BadCapacity
369	        );
370	        // Over the MPSC cap (fine for SPSC): tombstone headroom.
371	        assert_eq!(
372	            MpscRing::init(&mut r.0, 64, 1 << 31).err().unwrap(),
373	            Error::BadCapacity
374	        );
375	        assert_eq!(
376	            MpscRing::init(&mut r.0, 64, 8).err().unwrap(),
377	            Error::TooSmall
378	        );
379	        assert_eq!(
380	            MpscRing::init(&mut r.0[1..], 64, 4).err().unwrap(),
381	            Error::Misaligned
382	        );
383	        // 32-bit tripwire, as the SPSC test: N * M wraps a
384	        // 32-bit usize; the u64 region size must still reject.
385	        assert_eq!(
386	            MpscRing::init(&mut r.0, 1 << 26, 1 << 6).err().unwrap(),
387	            Error::TooSmall
388	        );
389	        // An SPSC-sized region (no seq line) is too small here.
390	        let spsc_bytes = size_of::<crate::Header>() + 4 * 64;
391	        assert_eq!(
392	            MpscRing::init(&mut r.0[..spsc_bytes], 64, 4).err().unwrap(),
393	            Error::TooSmall
394	        );
395	    }
