433	    #[test]
434	    fn cross_kind_attach_fails_bad_magic() {
435	        // An SPSC-initialized region is not an MPSC region…
436	        let mut r = Region::new();
437	        Ring::init(&mut r.0, 64, 4).unwrap();
438	        let err = unsafe { MpscRing::attach(r.0.as_mut_ptr(), r.0.len()) }
439	            .err()
440	            .unwrap();
441	        assert_eq!(err, Error::BadMagic);
442	        // …and an MPSC-initialized region is not an SPSC one.
443	        let mut r = Region::new();
444	        MpscRing::init(&mut r.0, 64, 4).unwrap();
445	        let err = unsafe { Ring::attach(r.0.as_mut_ptr(), r.0.len()) }
446	            .err()
447	            .unwrap();
448	        assert_eq!(err, Error::BadMagic);
449	    }
