585	    #[test]
586	    fn mpsc_panicking_fill_tombstones_and_skips() {
587	        let mut r = Region::new();
588	        let (prod, mut cons) = MpscRing::init(&mut r.0, 64, 4).unwrap().split();
589	
590	        // A committed message, a panicked fill, another
591	        // committed message.
592	        prod.send_with::<Msg>(|_| false, |m| m.seq = 1).unwrap();
593	        let unwound = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
594	            prod.send_with::<Msg>(
595	                |_| false,
596	                |m| {
597	                    m.seq = 99; // partially filled, then…
598	                    panic!("fill panics");
599	                },
600	            )
601	        }));
602	        assert!(unwound.is_err());
603	        prod.send_with::<Msg>(|_| false, |m| m.seq = 2).unwrap();
604	
605	        // The consumer sees 1 then 2; the tombstoned slot is
606	        // released without delivery.
607	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
608	        assert_eq!(msg.seq, 1);
609	        msg.release();
610	        let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
611	        assert_eq!(msg.seq, 2);
612	        msg.release();
613	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
614	
615	        // The skipped slot is claimable again: a full lap
616	        // still fits 4 messages.
617	        for i in 3..7u64 {
618	            prod.send_with::<Msg>(|_| false, |m| m.seq = i).unwrap();
619	        }
620	        assert!(prod.send_with::<Msg>(|_| false, |_| {}).is_err());
621	        for i in 3..7u64 {
622	            let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
623	            assert_eq!(msg.seq, i);
624	            msg.release();
625	        }
626	    }
627	
628	    #[test]
629	    fn mpsc_indices_survive_u32_wrap() {
630	        let mut r = Region::new();
631	        let ring = MpscRing::init(&mut r.0, 64, 4).unwrap();
632	        // Simulate a long-running ring two commits shy of the
633	        // u32 wrap: indices at MAX-1, and each slot's seq must
634	        // equal the free-running position that will next claim
635	        // it (positions MAX-1, MAX, 0, 1 → slots 2, 3, 0, 1).
636	        let start = u32::MAX - 1;
637	        ring.header.producer_idx.store(start, Ordering::Relaxed);
638	        ring.header.consumer_idx.store(start, Ordering::Relaxed);
639	        for (slot, pos) in [(2u32, u32::MAX - 1), (3, u32::MAX), (0, 0), (1, 1)] {
640	            // SAFETY: slot < capacity; test mirrors init.
641	            unsafe { &*ring.seqs.add(slot as usize) }.store(pos, Ordering::Relaxed);
642	        }
643	        let (prod, mut cons) = ring.split();
644	
645	        // Fill across the wrap, then Full.
646	        for i in 0..4u64 {
647	            prod.send_with::<Msg>(|_| false, |m| m.seq = i).unwrap();
648	        }
649	        assert!(prod.send_with::<Msg>(|_| false, |_| {}).is_err());
650	
651	        // Drain in order across the wrap.
652	        for i in 0..4u64 {
653	            let msg = cons.reserve_slot_with::<Msg>(|_| false).unwrap();
654	            assert_eq!(msg.seq, i);
655	            msg.release();
656	        }
657	        assert!(cons.reserve_slot_with::<Msg>(|_| false).is_err());
658	    }
